import {
  css,
  customElement,
  html,
  repeat,
  state,
  unsafeHTML,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import {
  UmbModalBaseElement,
  umbConfirmModal,
} from "@umbraco-cms/backoffice/modal";
import {
  RecordService,
  type FormSecurityForUser,
  type FieldData,
  type UpdateRecordField,
} from "@umbraco-forms/generated";
import type {
  UmbPropertyDatasetElement,
  UmbPropertyValueData,
} from "@umbraco-cms/backoffice/property";
import type { UmbPropertyEditorConfig } from "@umbraco-cms/backoffice/property-editor";
import { tryExecute } from "@umbraco-cms/backoffice/resources";
import { UMB_NOTIFICATION_CONTEXT } from "@umbraco-cms/backoffice/notification";
import type {
  FormsEntryDetailsModalData,
  FormsEntryDetailsModalValue,
} from "../token/form-entry-details-modal.token.js";
import type {
  FormEntryRecordAuditCollectionModel,
  FormEntryWorkflowAuditCollectionModel,
} from "../../section/forms/entries/types.js";
import { FORMS_FORM_WORKSPACE_CONTEXT } from "../../section/forms/workspace/form-workspace.context-token.js";
import { FORMS_CONTEXT } from "../../context/forms.context-token.js";
import {
  FormsFormEntryRecordAuditCollectionRepository,
  FormsFormEntryWorkflowAuditCollectionRepository,
} from "../../section/forms/entries/collection/repository/index.js";
import { EntryRenderHelper } from "../../section/forms/entries/entry-render-helper.class.js";

const elementName = "form-entry-details-modal";

@customElement(elementName)
export class FormsEntryDetailsModalElement extends UmbModalBaseElement<
  FormsEntryDetailsModalData,
  FormsEntryDetailsModalValue
> {
  #workspaceContext?: typeof FORMS_FORM_WORKSPACE_CONTEXT.TYPE;

  #workflowAudit: Array<FormEntryWorkflowAuditCollectionModel> = [];
  #recordAudit: Array<FormEntryRecordAuditCollectionModel> = [];

  @state()
  private _editModeActive: boolean = false;

  #currentFieldValues: Array<FieldData> = [];
  #currentValidationErrors: Record<string, Array<string>> = {};

  #userSecurity?: FormSecurityForUser;

  constructor() {
    super();

    this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, (instance) => {
      this.#workspaceContext = instance;
    });

    this.consumeContext(FORMS_CONTEXT, (context) => {
      if (!context) return;
      this.observe(context.userSecurity, (userSecurity) => {
        this.#userSecurity = userSecurity;
      });
    });
  }

  async connectedCallback(): Promise<void> {
    super.connectedCallback();

    await this.#refreshWorkflowAudit();
    await this.#refreshRecordAudit();
  }

  #getSubmissionFields() {
    return this.value.fields.filter((field) => !this.#isSystemField(field));
  }

  #getSubmissionFieldValues(): Array<UmbPropertyValueData> {
    const values = this.#getSubmissionFields().map((f) => {
      return {
        alias: f.fieldId,
        value: this._editModeActive
          ? this.#getSubmissionFieldValueForEditor(f)
          : this.#getSubmissionFieldValueForDisplay(f),
      };
    });
    return values;
  }

  #getSubmissionFieldValueForDisplay(fieldData: FieldData) {
    const schemaItem = this.#getSchemaItem(fieldData);
    if (!schemaItem) {
      return html`${fieldData.value}`;
    }

    const entryRenderHelper = new EntryRenderHelper(this, this.data?.fieldPrevalues || []);
    if (schemaItem.view === "file") {
      return unsafeHTML(this.#getFilePreview(fieldData));
    } else {
      const value = entryRenderHelper.getRenderValue(fieldData, schemaItem.view);
      return html`${value}`;
    }
  }

  #getFilePreview(fieldData: FieldData) {
    const imageExtensions = ['jpg', 'jpeg', 'png', 'gif', 'bmp'];
    if (!fieldData.value) {
      return "";
    }

    const filePaths = fieldData.value.toString().split(", ");
    let previewHtml = "";
    for (let index = 0; index < filePaths.length; index++) {
      const filePath = filePaths[index];
      const extension = filePath.substring(filePath.lastIndexOf(".") + 1).toLowerCase();
      previewHtml += "<div>";
      if (imageExtensions.indexOf(extension) >= 0) {
        previewHtml +=`<a target="_blank" href="${filePath}"><img src="${filePath}" width="200" /></a>`;
      } else {
        const fileName = filePath.substring(filePath.lastIndexOf("/") + 1);
        previewHtml += `<a target="_blank" href="${filePath}">${fileName}</a>`;
      }
      previewHtml += "</div>";
    }

    return previewHtml;
  }

  #getSubmissionFieldValueForEditor(fieldData: FieldData) {
    // Transform the string value into the type appropriate for the property editor.
    const schemaItem = this.#getSchemaItem(fieldData);
    if (!schemaItem) {
      return null;
    }

    const value = fieldData.value?.toString() || "";

    switch (schemaItem.editView) {
      case "Umb.PropertyEditorUi.Toggle":
        return value.toLowerCase() === "true";
      case "Umb.PropertyEditorUi.Dropdown": {
        const field = this.#getField(schemaItem.alias);
        if (
          field?.settings["AllowMultipleSelections"]?.toLowerCase() === "true"
        ) {
          const values = this.#getSubmissionFieldValueForEditorWithPrevalues(
            fieldData.fieldId,
            value.split(",").map((v) => v.trim())
          );
          return this._editModeActive ? values : values.join(", ");
        } else {
          return this.#getSubmissionFieldValueForEditorWithPrevalues(
            fieldData.fieldId,
            [value]
          );
        }
      }
      case "Umb.PropertyEditorUi.RadioButtonList":
        return this.#getSubmissionFieldValueForEditorWithPrevalues(
          fieldData.fieldId,
          [value]
        )[0];
      case "Umb.PropertyEditorUi.CheckBoxList": {
        // In edit view we need an array of values, in display view a comma delimited string.
        const values = this.#getSubmissionFieldValueForEditorWithPrevalues(
          fieldData.fieldId,
          value.split(",").map((v) => v.trim())
        );
        return this._editModeActive ? values : values.join(", ");
      }
      case "Umb.PropertyEditorUi.DatePicker":
        return this._editModeActive
          ? value
          : new Date(value).toLocaleDateString();
      default:
        return value;
    }
  }

  #getSubmissionFieldValueForEditorWithPrevalues(
    fieldId: string,
    values: Array<string>
  ) {
    const result: Array<string> = [];

    for (let i = 0; i < values.length; i++) {
      const value = values[i];

      if (value.length === 0) {
        continue;
      }

      // If we have prevalues with captions, display those instead of the stored value.
      const prevalues = this.#getPrevaluesForField(fieldId);
      const matchedPrevalue = prevalues.find((x) => x.value === value);
      const valueForEditor =
        matchedPrevalue?.caption && matchedPrevalue.caption.length > 0
          ? matchedPrevalue?.caption
          : value;
      result.push(valueForEditor);
    }

    return result;
  }

  #getPrevaluesForField(fieldId: string) {
    return (
      this.data?.fieldPrevalues.find((f) => f.id === fieldId)?.prevalues || []
    );
  }

  #isSystemField(field: FieldData) {
    // Non-system fields are have GUIDs for Ids. Hat-tip: https://stackoverflow.com/a/68837405
    const isHex = (c: string) => "0123456789abcdef".includes(c.toLowerCase());

    const isGuid = (input: string) => {
      input = input.replace(/-/g, "");
      return input.length === 32 && [...input].every(isHex);
    };

    return !isGuid(field.fieldId);
  }

  #getFieldName(field: FieldData) {
    const schemaItem = this.#getSchemaItem(field);
    return schemaItem?.name;
  }

  #getFieldEditView(field: FieldData) {
    const schemaItem = this.#getSchemaItem(field);
    return schemaItem?.editView;
  }

  #getSubmissionFieldEditablePropertyConfig(
    field: FieldData
  ): UmbPropertyEditorConfig {
    const config: UmbPropertyEditorConfig = [];
    if (!this._editModeActive) {
      return config;
    }

    const schemaItem = this.#getSchemaItem(field);
    if (!schemaItem) {
      return config;
    }

    // TODO: Somehow we need to make this extensible by people defining their own field types with custom edit views.
    switch (schemaItem.editView) {
      case "Umb.PropertyEditorUi.Dropdown": {
        const field = this.#getField(schemaItem.alias);
        if (field) {
          config.push({
            alias: "multiple",
            value:
              field.settings["AllowMultipleSelections"]?.toLowerCase() ===
              "true",
          });
          config.push({
            alias: "items",
            value: this.#getPrevaluesForField(field.id).map((pv) =>
              pv.caption && pv.caption.length > 0 ? pv.caption : pv.value
            ),
          });
        }
        break;
      }
      case "Umb.PropertyEditorUi.RadioButtonList":
      case "Umb.PropertyEditorUi.CheckBoxList": {
        const field = this.#getField(schemaItem.alias);
        if (field) {
          config.push({
            alias: "items",
            value: this.#getPrevaluesForField(field.id).map((pv) =>
              pv.caption && pv.caption.length > 0 ? pv.caption : pv.value
            ),
          });
        }
        break;
      }
    }

    return config;
  }

  #getField(alias: string) {
    const formFields = this.#workspaceContext?.getAllFields() || [];
    return formFields.find((f) => f.alias === alias);
  }

  #getSchemaItem(field: FieldData) {
    return this.#getSchemaItemByFieldId(field.fieldId);
  }

  #getSchemaItemByFieldId(fieldId: string) {
    return this.data?.schema.find((s) => s.id === fieldId);
  }

  #toggleEditMode() {
    this._editModeActive = !this._editModeActive;
    if (this._editModeActive) {
      // Save the current field values so we can compare to see what has changed on save.
      this.#currentFieldValues = this.#getSubmissionFields();
    } else {
      this.#currentFieldValues = [];
    }

    this.#currentValidationErrors = {};
  }

  #hasValidationError(fieldId: string) {
    return this.#currentValidationErrors[fieldId]?.length > 0;
  }

  #getValidationErrors(fieldId: string): Array<string> {
    return this.#currentValidationErrors[fieldId];
  }

  async #saveUpdatedValues() {
    const fieldValues: Array<UpdateRecordField> = [];

    const currentFieldValues = this.#currentFieldValues;
    const newFieldValues = this.#getFieldValuesFromElement();

    for (let i = 0; i < currentFieldValues.length; i++) {
      const currentValue = currentFieldValues[i];
      const newValue = newFieldValues[i];
      if (currentValue.value !== newValue.values.join(",")) {
        fieldValues.push(newValue);
      }
    }

    if (fieldValues.length === 0) {
      this.#resetAfterSave();
      return;
    }

    const request = {
      recordId: this.value?.unique || "",
      formId: this.#workspaceContext?.getUnique() || "",
      requestBody: fieldValues,
    };

    const { error } = await tryExecute(
      RecordService.putFormByFormIdRecordByRecordId(request)
    );

    if (error) {
      // Had a problem, display validation errors.
      this.#currentValidationErrors = error["body"]["errors"];
      this.requestUpdate();
      return;
    }

    // All good, so switch back to view mode, display a notification and update the local model.
    this.#resetAfterSave();

    const notification = {
      data: {
        message: this.localize.term("formEntries_updateRecordSuccess"),
      },
    };

    const notificationContext = await this.getContext(UMB_NOTIFICATION_CONTEXT);
    notificationContext?.peek("positive", notification);

    const fields = structuredClone(this.value?.fields);
    for (let i = 0; i < fieldValues.length; i++) {
      const fieldValue = fieldValues[i];
      fields.find((f) => f.fieldId === fieldValue.fieldId)!.value =
        fieldValue.values;
    }

    this.modalContext?.updateValue({ fields, updateCollection: true });
  }

  #resetAfterSave() {
    this._editModeActive = false;
    this.#currentValidationErrors = {};
    this.#currentFieldValues = [];
  }

  #getFieldValuesFromElement() {
    const formSubmissionFieldsElement = this.shadowRoot?.getElementById(
      "formSubmissionFields"
    ) as UmbPropertyDatasetElement;
    if (!formSubmissionFieldsElement)
      throw new Error("Could not find form submission fields element.");

    const values: Array<UpdateRecordField> = [];
    for (let i = 0; i < formSubmissionFieldsElement.value.length; i++) {
      const item = formSubmissionFieldsElement.value[i];
      values.push({
        fieldId: item.alias,
        values: this.#getFieldValueForPersistence(item.alias, item),
      });
    }

    return values;
  }

  #getFieldValueForPersistence(
    fieldId: string,
    valueData: UmbPropertyValueData
  ): Array<unknown> {
    // Transform the editor value into an array of values for persistence.
    const schemaItem = this.#getSchemaItemByFieldId(valueData.alias);
    if (!schemaItem) {
      return [];
    }

    switch (schemaItem.editView) {
      case "Umb.PropertyEditorUi.Dropdown":
      case "Umb.PropertyEditorUi.RadioButtonList":
      case "Umb.PropertyEditorUi.CheckBoxList": {
        // As these property editors only supports strings and not Options for it's items, we'll potentially have a caption
        // here that we need to map back to the value.
        const selectedValues = Array.isArray(valueData.value)
          ? (valueData.value as Array<string>)
          : [valueData.value];
        if (selectedValues.length === 0) {
          return [];
        }

        const prevalues = this.#getPrevaluesForField(fieldId);
        return selectedValues.map((v) => {
          const prevalueMatchedToCaption = prevalues.find(
            (pv) => pv.caption === v
          );
          return prevalueMatchedToCaption ? prevalueMatchedToCaption.value : v;
        });
      }
      default:
        return [valueData.value];
    }
  }

  async #refreshWorkflowAudit() {
    const formId = this.#workspaceContext?.getUnique();
    if (!formId) return [];

    const recordId = this.value.unique;

    const repo = new FormsFormEntryWorkflowAuditCollectionRepository(this);
    await this.#retrieveWorkflowAudit(repo, formId, recordId);
  }

  async #retrieveWorkflowAudit(
    repo: FormsFormEntryWorkflowAuditCollectionRepository,
    formId: string,
    recordId: string
  ) {
    const response = await repo.requestCollection({ formId, recordId });
    this.#workflowAudit = response?.data?.items || [];
    this.requestUpdate();
  }

  async #refreshRecordAudit() {
    const formId = this.#workspaceContext?.getUnique();
    if (!formId) return [];

    const recordId = this.value.unique;

    const repo = new FormsFormEntryRecordAuditCollectionRepository(this);
    const response = await repo.requestCollection({ formId, recordId });
    this.#recordAudit = response?.data?.items || [];
    this.requestUpdate();
  }

  async #runWorkflow(workflowKey: string) {
    const formId = this.#workspaceContext?.getUnique();
    if (!formId) return;

    const recordId = this.value.unique;

    await umbConfirmModal(this, {
      headline: this.localize.term(
        "formEntries_workflowAuditRetryConfirmTitle"
      ),
      content: this.localize.term(
        "formEntries_workflowAuditRetryConfirmMessage"
      ),
      confirmLabel: this.localize.term("general_yes"),
      color: "positive",
    });

    const repo = new FormsFormEntryWorkflowAuditCollectionRepository(this);
    await repo.executeWorkflow(formId, recordId, workflowKey);
    await this.#retrieveWorkflowAudit(repo, formId, recordId);
  }

  #goToDocument() {
    history.pushState(
      {},
      "",
      `/umbraco/section/content/workspace/document/edit/${this.value.documentUnique}`
    );
    this._rejectModal();
  }

  #renderMember() {
    if (!this.value.member?.unique) return null;

    const goToMember = () => {
      history.pushState(
        {},
        "",
        `/umbraco/section/member-management/workspace/member/edit/${
          this.value.member!.unique
        }`
      );
      this._rejectModal();
    };

    return html` <umb-property-layout
      label=${this.localize.term("formEntries_member")}
    >
      <uui-ref-node-member
        slot="editor"
        name=${this.value.member.name}
        group-name=${this.value.member.email}
      >
        <uui-action-bar slot="actions">
          <uui-button
            label=${this.localize.term("general_edit")}
            @click=${goToMember}
          ></uui-button>
        </uui-action-bar>
      </uui-ref-node-member>
    </umb-property-layout>`;
  }

  #renderEditingControls() {
    if (!this.#userSecurity?.userSecurity.editEntries) return null;

    return html`<div id="edit">
      ${when(
        this._editModeActive,
        () => html` <uui-button
            @click=${this.#toggleEditMode}
            look="default"
            label=${this.localize.term("general_cancel")}
          ></uui-button>
          <uui-button
            @click=${this.#saveUpdatedValues}
            look="primary"
            color="positive"
            label=${this.localize.term("buttons_save")}
          ></uui-button>`,
        () => html`<uui-button
          @click=${this.#toggleEditMode}
          look="primary"
          label=${this.localize.term("general_edit")}
        ></uui-button>`
      )}
    </div>`;
  }

  render() {
    return html`<umb-body-layout
      headline=${this.localize.term("formEntries_entryDetails")}
    >
      <uui-box
        headline=${this.localize.term("formEntries_formSubmissionHeadline")}
      >
        <umb-property-dataset
          id="formSubmissionFields"
          .value=${this.#getSubmissionFieldValues()}
        >
          ${repeat(
            this.#getSubmissionFields(),
            (field) => field.fieldId,
            (field) => html`<umb-property
                .label=${this.#getFieldName(field) ?? ""}
                alias=${field.fieldId}
                .config=${this.#getSubmissionFieldEditablePropertyConfig(field)}
                property-editor-ui-alias="${this._editModeActive
                  ? this.#getFieldEditView(field) ??
                    "Umb.PropertyEditorUi.Label"
                  : "Umb.PropertyEditorUi.Label"}"
              >
              </umb-property>
              ${when(
                this.#hasValidationError(field.fieldId),
                () => html`<div class="validation-error">
                  ${this.#getValidationErrors(field.fieldId).map(
                    (e) => html`<div>${e}</div>`
                  )}
                </div>`
              )} `
          )}
        </umb-property-dataset>
        ${this.#renderEditingControls()}
      </uui-box>

      <uui-box headline=${this.localize.term("general_general")}>
        <umb-property-layout
          label=${this.localize.term("formEntries_submittedOn")}
        >
          <div slot="editor">${this.value.created.toLocaleString()}</div>
        </umb-property-layout>
        ${when(
          this.value.updated !== this.value.created,
          () => html`<umb-property-layout
            label=${this.localize.term("formEntries_updatedOn")}
          >
            <div slot="editor">${this.value.updated.toLocaleString()}</div>
          </umb-property-layout>`
        )}
        ${when(
          this.value.pageName && this.value.pageName.length > 0,
          () => html`<umb-property-layout
            label=${this.localize.term("formEntries_fromPage")}
          >
            <div slot="editor" id="document">
              <span>${this.value.pageName}</span>
              <uui-button
                look="primary"
                color="default"
                @click=${this.#goToDocument}
                label=${this.localize.term("formEntries_goToDocument")}
              ></uui-button>
            </div>
          </umb-property-layout>`
        )}
        ${this.#renderMember()}

        <umb-property-layout label=${this.localize.term("formEntries_state")}>
          <div slot="editor">${this.value.state}</div>
        </umb-property-layout>
        <umb-property-layout label=${this.localize.term("general_id")}>
          <div slot="editor">${this.value.id}</div>
        </umb-property-layout>
        <umb-property-layout
          label=${this.localize.term("formEntries_uniqueId")}
        >
          <div slot="editor">${this.value.unique}</div>
        </umb-property-layout>
      </uui-box>

      ${when(
        this.#workflowAudit.length > 0,
        () => html`<uui-box headline=${this.localize.term("formEntries_workflowAudit")}>
          <uui-table>
            <uui-table-head>
              <uui-table-head-cell>
                ${this.localize.term("formEntries_workflowAuditName")}
              </uui-table-head-cell>
              <uui-table-head-cell>
                ${this.localize.term("formEntries_workflowAuditType")}
              </uui-table-head-cell>
              <uui-table-head-cell>
                ${this.localize.term("formEntries_workflowAuditExecutedOn")}
              </uui-table-head-cell>
              <uui-table-head-cell>
                ${this.localize.term("formEntries_workflowAuditExecutionStage")}
              </uui-table-head-cell>
              <uui-table-head-cell>
                ${this.localize.term("formEntries_workflowAuditResult")}
              </uui-table-head-cell>
              <uui-table-head-cell></uui-table-head-cell>
            </uui-table-head>
            ${this.#workflowAudit.map(
              (record) =>
                html`<uui-table-row>
                  <uui-table-cell>${record.name}</uui-table-cell>
                  <uui-table-cell>${record.typeName}</uui-table-cell>
                  <uui-table-cell
                    >${record.executedOn.toLocaleString()}</uui-table-cell
                  >
                  <uui-table-cell>
                    ${this.localize.term(
                      "formEntries_workflowExecutionStage" +
                        record.executionStage
                    )}
                  </uui-table-cell>
                  <uui-table-cell>${record.result}</uui-table-cell>
                  <uui-table-cell>
                    <uui-button
                      label=${this.localize.term("formEntries_runWorkflow")}
                      @click="${() => this.#runWorkflow(record.workflowKey)}"
                    >
                      ${this.localize.term(
                        record.result === "Completed"
                          ? "formEntries_workflowAuditRunAgain"
                          : record.result === "SkippedDueToConditions"
                            ? "formEntries_workflowAuditRunAnyway"
                            : "formEntries_workflowAuditRetry"
                      )}
                    </uui-button>
                  </uui-table-cell>
                </uui-table-row>`
            )}
          </uui-table>
        </uui-box>`
      )}
      ${when(
        this.#recordAudit.length > 0,
        () => html`<uui-box headline=${this.localize.term("formEntries_recordAudit")}>
          <uui-table>
            <uui-table-head>
              <uui-table-head-cell
                >${this.localize.term(
                  "formEntries_updatedOn"
                )}</uui-table-head-cell
              >
              <uui-table-head-cell
                >${this.localize.term(
                  "formEntries_updatedBy"
                )}</uui-table-head-cell
              >
            </uui-table-head>
            ${this.#recordAudit.map(
              (record) =>
                html`<uui-table-row>
                  <uui-table-cell
                    >${record.updatedOn.toLocaleString()}</uui-table-cell
                  >
                  <uui-table-cell>${record.updatedBy}</uui-table-cell>
                </uui-table-row>`
            )}
          </uui-table>
        </uui-box>`
      )}
      <!-- submitting is intentional to ensure result is returned to the callee, indicating whether
      the collection should be updated (ie modal had saved changes) -->
      <uui-button
        slot="actions"
        label=${this.localize.term("general_close")}
        @click=${this._submitModal}
      ></uui-button>
    </umb-body-layout>`;
  }

  static styles = [
    css`
      uui-box {
        display: block;
      }
      uui-box + uui-box {
        margin-top: var(--uui-size-layout-1);
      }

      uui-table {
        width: 100%;
      }

      .validation-error {
        color: red;
      }

      #document {
        display: flex;
        justify-content: space-between;
      }

      #document uui-button {
        margin-left: var(--uui-size-6);
      }

      #edit {
        display: flex;
        justify-content: end;
        column-gap: var(--uui-size-3);
      }
    `,
  ];
}

export default FormsEntryDetailsModalElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsEntryDetailsModalElement;
  }
}
